import { defineConfig } from "vitepress"
import { readFileSync } from "node:fs"
import { fileURLToPath } from "node:url"

// Sidebar for /reference/ is generated by sync-modules.mjs (runs before build).
// Fall back to an empty object before the first sync so config never crashes.
let referenceSidebar = {}
try {
  referenceSidebar = JSON.parse(
    readFileSync(fileURLToPath(new URL("./sidebar.json", import.meta.url)), "utf-8"),
  )
} catch {
  /* sidebar.json not generated yet */
}

// https://vitepress.dev/reference/site-config
export default defineConfig({
  title: "Regira Modules",
  description: "The Regira front-end library — TypeScript & Vue 3 building blocks.",
  // Project page is served from https://regira.github.io/Regira-JsLib/
  base: "/Regira-JsLib/",
  cleanUrls: true,
  // The ingested module docs contain links to source files (e.g. src/vue/...) that
  // don't exist inside the docs site; don't fail the build on those.
  ignoreDeadLinks: true,
  themeConfig: {
    nav: [
      { text: "Guide", link: "/guide/getting-started" },
      { text: "Modules", link: "/guide/module-stack" },
      { text: "Reference", link: "/reference/vue-entities/" },
    ],
    sidebar: {
      "/guide/": [
        {
          text: "Guide",
          items: [
            { text: "Getting started", link: "/guide/getting-started" },
            { text: "Module stack", link: "/guide/module-stack" },
          ],
        },
      ],
      ...referenceSidebar,
    },
    socialLinks: [{ icon: "github", link: "https://github.com/Regira/Regira-JsLib" }],
    search: { provider: "local" },
    editLink: {
      pattern: "https://github.com/Regira/Regira-JsLib/edit/main/:path",
    },
  },
})
